import { NextResponse } from "next/server";
import path from "path";
import fs from "fs";
import { products as sourceProducts } from "@/data/products";

// Match the Product interface shape used in data/products
interface Product {
  id: number;
  name: string;
  description: string;
  shortDescription: string;
  imageUrl: string;
  category: string;
  subcategory: string | null;
  size: string | null;
  stockStatus: string;
  isFeatured: boolean;
}

function toTitleCase(name: string) {
  return name
    .replace(/[-_]+/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (c) => c.toUpperCase());
}

export async function GET() {
  try {
    const dir = path.join(process.cwd(), "public", "products");
    const entries = fs.existsSync(dir) ? fs.readdirSync(dir, { withFileTypes: true }) : [];
    const imageFiles = entries
      .filter((e) => e.isFile())
      .map((e) => e.name)
      .filter((n) => /(jpe?g|png|webp|gif)$/i.test(n));

    function findBestImageForId(id: number): string | null {
      // Prefer exact matches like 1050.jpg
      const exact = imageFiles.find((f) => new RegExp(`^${id}\\.(?:jpe?g|png|webp|gif)$`, "i").test(f));
      if (exact) return `/products/${exact}`;
      // Fallback to variants like 1050b.jpg or 1050c.png
      const variant = imageFiles.find((f) => new RegExp(`^${id}[a-z]\\.(?:jpe?g|png|webp|gif)$`, "i").test(f));
      if (variant) return `/products/${variant}`;
      return null;
    }

    const products = sourceProducts.map((p, idx) => {
      const img = findBestImageForId(p.id);
      return {
        ...p,
        imageUrl: img ?? p.imageUrl,
        id: p.id ?? idx + 1,
      } satisfies Product;
    });

    return NextResponse.json(products);
  } catch (err) {
    console.error("Error loading products from public/products:", err);
    return NextResponse.json({ error: "Failed to load products" }, { status: 500 });
  }
}
